def forward(self, taskInfo):
    import json
    import re
    from datetime import datetime, timedelta

    # ---------- Step 1: Process input ----------
    # Extract input data from taskInfo
    if isinstance(taskInfo.content, dict):
        input_data = taskInfo.content
    elif isinstance(taskInfo.content, str):
        try:
            input_data = json.loads(taskInfo.content)
        except:
            input_data = {}
    else:
        input_data = {}

    constraints = input_data.get('constraints', {})
    filtered_context = input_data.get('filtered_context', '')

    budget = float(constraints.get('budget', 11000))
    duration = int(constraints.get('duration_days', 7))
    start_date_str = constraints.get('start_date', '2022-03-10')
    people_count = int(constraints.get('people_count', 4))

    # Normalize constraints for accommodation
    req_room_type = "Entire home/apt"

    # ---------- Step 2: Intelligent Parsing ----------
    def parse_table(text):
        lines = text.strip().split('\n')
        if len(lines) < 2: return [], []
        headers = re.split(r'\s{2,}|\t', lines[0].strip())
        data = []
        for line in lines[1:]:
            parts = re.split(r'\s{2,}|\t', line.strip())
            if len(parts) >= len(headers) - 1:
                row = {}
                for i, h in enumerate(headers):
                    if i < len(parts):
                        row[h.lower()] = parts[i]
                data.append(row)
        return data

    # 2a. Parse Flights
    flight_sections = re.findall(r'Description: Flight from ([A-Za-z\s]+) to ([A-Za-z\s]+) on (\d{4}-\d{2}-\d{2}).*?Content:(.*?)(?=\n\n|\Z)', filtered_context, re.DOTALL | re.IGNORECASE)

    all_flights = []
    for origin, dest, date_str, content in flight_sections:
        rows = parse_table(content)
        for r in rows:
            try:
                price = float(r.get('price', 0))
                num = r.get('flight number', 'Unknown')
                dep = r.get('deptime', '00:00')
                arr = r.get('arrtime', '00:00')
                all_flights.append({
                    'origin': origin.strip(),
                    'dest': dest.strip(),
                    'date': date_str,
                    'price': price,
                    'details': f"Flight Number: {num}, from {origin.strip()} to {dest.strip()}, Departure Time: {dep}, Arrival Time: {arr}"
                })
            except:
                continue

    # 2b. Parse Accommodations
    acc_sections = re.findall(r'Description: Accommodations in ([A-Za-z\s]+).*?Content:(.*?)(?=\n\n|\Z)', filtered_context, re.DOTALL | re.IGNORECASE)

    city_hotels = {}
    for city, content in acc_sections:
        city = city.strip()
        rows = parse_table(content)
        valid_hotels = []
        for r in rows:
            try:
                price = float(r.get('price', 0))
                occupancy = float(r.get('maximum occupancy', 0))
                room_type = r.get('room type', '')
                house_rules = r.get('house_rules', '')
                name = r.get('name', 'Unknown')

                if occupancy < people_count:
                    continue
                if req_room_type.lower() not in room_type.lower():
                    continue
                if 'no parties' in house_rules.lower():
                    continue

                valid_hotels.append({
                    'name': name,
                    'price': price,
                    'city': city,
                    'details': f"{name}, {city}"
                })
            except:
                continue
        valid_hotels.sort(key=lambda x: x['price'])
        city_hotels[city] = valid_hotels

    # ---------- Step 3: Build Trip Skeleton ----------
    all_flights.sort(key=lambda x: x['date'])

    selected_flights = {}
    for f in all_flights:
        key = f"{f['date']}_{f['origin']}_{f['dest']}"
        if key not in selected_flights:
            selected_flights[key] = f
        else:
            if f['price'] < selected_flights[key]['price']:
                selected_flights[key] = f

    sorted_moves = sorted(selected_flights.values(), key=lambda x: x['date'])

    try:
        start_date = datetime.strptime(start_date_str, "%Y-%m-%d")
    except:
        start_date = datetime(2022, 3, 10)

    skeleton_lines = []
    current_city = constraints.get('origin_city', 'Seattle')
    current_hotel = "-"

    trip_days = []
    for i in range(duration):
        d = start_date + timedelta(days=i)
        d_str = d.strftime("%Y-%m-%d")

        move = None
        for m in sorted_moves:
            if m['date'] == d_str and m['origin'].lower() == current_city.lower():
                move = m
                break

        day_info = {}
        day_info['day'] = i + 1

        if move:
            dest = move['dest']
            day_info['current_city'] = f"from {current_city} to {dest}"
            day_info['transportation'] = move['details']
            current_city = dest
            if current_city in city_hotels and city_hotels[current_city]:
                current_hotel = city_hotels[current_city][0]['details']
            else:
                found = False
                for c_key in city_hotels:
                    if c_key.lower() in current_city.lower() or current_city.lower() in c_key.lower():
                        current_hotel = city_hotels[c_key][0]['details']
                        found = True
                        break
                if not found:
                    current_hotel = "Unknown Accommodation"
            day_info['accommodation'] = current_hotel
        else:
            day_info['current_city'] = current_city
            day_info['transportation'] = "-"
            day_info['accommodation'] = current_hotel

        trip_days.append(day_info)
        skeleton_lines.append(json.dumps(day_info))

    skeleton_str = "\n".join(skeleton_lines)

    # ---------- Step 4: LLM Call ----------
    system_prompt = f"""You are an expert Travel Planner. Your task is to generate a {duration}-day travel itinerary in valid JSON format based on the provided constraints and data.

**TRIP SKELETON (MUST FOLLOW):**
Use the following pre-calculated logistics for the itinerary. The trip structure is dictated by available flight dates.
{skeleton_str}

**INSTRUCTIONS:**
1. **Fill in the Details**: For each day, keep the 'current_city', 'transportation', and 'accommodation' EXACTLY as provided in the Skeleton above. You only need to select suitable Restaurants (Breakfast, Lunch, Dinner) and Attractions from the Reference Information for that city.
2. **Consistency**: Ensure all details (names, flight numbers) are copied exactly from the data.
3. **Formatting**: 
   - 'current_city' for travel days: 'from [Origin] to [Dest]'.
   - 'current_city' for stay days: '[City]'.
   - Use '-' for fields where no activity is needed (e.g., Transportation on stay days).
4. **No Parties Check**: The user requested accommodations that allow parties. The skeleton has already filtered for this. Do not change the accommodation.

**OUTPUT SCHEMA:**
Return a JSON object with a single key "plan" containing a list of day objects:
{{
  "plan": [
    {{
      "days": 1,
      "current_city": "String",
      "transportation": "String",
      "breakfast": "String",
      "attraction": "String",
      "lunch": "String",
      "dinner": "String",
      "accommodation": "String"
    }}
  ]
}}
"""

    user_prompt = f"""
    **Constraints**:
    - Budget: ${budget}
    - Duration: {duration} days
    - Travelers: {people_count}
    - Dates: {start_date_str} to {constraints.get('end_date', 'Unknown')}

    **Reference Information**:
    {filtered_context}

    **Task**: Generate the full {duration}-day itinerary JSON.
    **Response**:
    """

    # Combine instructions for the agent
    cot_instruction = system_prompt + "\n\n" + user_prompt

    # Instantiate the LLM agent
    cot_agent = LLMAgentBase(['thinking', 'answer'], 'ItineraryPlanner_Agent', model=self.node_model, temperature=0.0)

    # Call the agent
    try:
        thinking, answer = cot_agent([taskInfo], cot_instruction)
        response_content = answer.content
    except Exception as e:
        print(f"LLM Call failed: {e}")
        return self.make_final_answer(None, json.dumps({"draft_itinerary": []}))

    # ---------- Step 5: Output Parsing ----------
    draft = []
    try:
        response_str = response_content
        # Try to extract JSON block if wrapped in text
        json_block_match = re.search(r'\{.*\}', response_str, re.DOTALL)
        if json_block_match:
            try:
                response_data = json.loads(json_block_match.group(0))
            except:
                # Fallback to loading whole string if strict block load fails
                response_data = json.loads(response_str)
        else:
            response_data = json.loads(response_str)

        if 'plan' in response_data and isinstance(response_data['plan'], list):
            draft = response_data['plan']
        elif isinstance(response_data, list):
            draft = response_data
        elif isinstance(response_data, dict):
            # Look for any list value
            for v in response_data.values():
                if isinstance(v, list):
                    draft = v
                    break

        # Clean and validate keys
        final_draft = []
        required_keys = ["days", "current_city", "transportation", "breakfast", "attraction", "lunch", "dinner", "accommodation"]

        for i, item in enumerate(draft):
            if not isinstance(item, dict): continue
            cleaned = {}
            cleaned['days'] = item.get('days', i + 1)
            for k in required_keys:
                if k == 'days': continue
                val = item.get(k, '-')
                cleaned[k] = str(val) if val is not None else '-'
            final_draft.append(cleaned)

        draft = final_draft

    except Exception as e:
        print(f"Error parsing LLM response: {e}")
        draft = []

    # Prepare final answer content as JSON string to match original return structure
    final_output = {"draft_itinerary": draft}
    answer.content = json.dumps(final_output)

    return self.make_final_answer(thinking, answer)

def forward(self, taskInfo):
    # Extract input data from taskInfo
    # The content might be a dict or a JSON string
    content = taskInfo.content
    if isinstance(content, dict):
        input_data = content
    elif isinstance(content, str):
        try:
            input_data = json.loads(content)
        except:
            input_data = {}
    else:
        input_data = {}

    reference_info = input_data.get('reference_information', [])
    constraints = input_data.get('constraints', {})
    query = input_data.get('query', '') or input_data.get('question', '')
    query_lower = query.lower()

    # --- 1. Constraint Extraction ---
    def clean_cost(s):
        if not s or str(s).strip() in ['-', 'Unknown']: return 0.0
        try:
            val = re.sub(r'[^\d.]', '', str(s))
            return float(val) if val and val != '.' else 0.0
        except: return 0.0

    budget = clean_cost(constraints.get('budget', 0))
    if budget == 0:
        m_budget = re.search(r'\$(\d+(?:,\d+)?)', query)
        if m_budget: budget = float(m_budget.group(1).replace(',', ''))
        else: budget = float('inf')

    people = 1
    if 'people_count' in constraints and constraints['people_count']:
        try: people = int(constraints['people_count'])
        except: pass
    else:
        m_people = re.search(r'(\d+)\s+people', query_lower)
        if m_people: people = int(m_people.group(1))

    start_date_str = constraints.get('start_date')
    end_date_str = constraints.get('end_date')
    total_nights = 1
    if start_date_str and end_date_str:
        try:
            d1 = datetime.strptime(start_date_str, "%Y-%m-%d")
            d2 = datetime.strptime(end_date_str, "%Y-%m-%d")
            total_nights = (d2 - d1).days
        except: pass
    if total_nights < 1: total_nights = 1

    avoid_driving = any(x in query_lower for x in ['no driving', 'not drive', 'avoid driving'])
    avoid_flying = any(x in query_lower for x in ['no flight', 'not take flight', 'avoid flying', 'without flying'])
    require_entire = 'entire' in query_lower
    has_children = any(x in query_lower for x in ['children', 'kid', 'under 10'])
    has_pets = 'pet' in query_lower

    target_cuisines = [c.strip() for c in query_lower.replace(',', ' ').split() 
                       if c in ['american', 'chinese', 'french', 'italian', 'indian', 'mexican', 'mediterranean', 'seafood', 'bbq', 'pizza', 'bakery', 'cafe']]

    # --- 2. Smart City Discovery ---
    known_cities = set()
    if constraints.get('origin_city'): known_cities.add(constraints['origin_city'].lower())
    if constraints.get('destination_city'): known_cities.add(constraints['destination_city'].lower())

    # Scan for implicit cities in the data headers and descriptions
    for item in reference_info:
        desc = item.get('Description', '')
        # "Attractions in Toledo"
        m_in = re.search(r'(?:Attractions|Accommodations|Restaurants)\s+in\s+([A-Za-z\.\s]+)$', desc, re.IGNORECASE)
        if m_in:
            known_cities.add(m_in.group(1).strip().lower())
        # "from Toledo to Cleveland"
        m_route = re.search(r'from\s+([A-Za-z\.\s]+?)\s+to\s+([A-Za-z\.\s]+)', desc, re.IGNORECASE)
        if m_route:
            known_cities.add(m_route.group(1).strip().lower())
            known_cities.add(m_route.group(2).strip().lower())

    # --- 3. Robust Table Parser ---
    def parse_table(content, category):
        if not content or "no flight" in content.lower(): return []
        lines = [line.strip() for line in content.strip().split('\n') if line.strip()]
        if len(lines) < 2: return []

        # Header processing
        header_line = lines[0]
        headers = [h.lower() for h in re.split(r'\s{2,}', header_line)]

        results = []
        for line in lines[1:]:
            row = {}
            parts = re.split(r'\s{2,}', line)

            # Handle Pandas Index: if row has 1 more column than header and first is int
            if len(parts) == len(headers) + 1 and parts[0].replace('.', '').isdigit():
                parts.pop(0)

            # Anchor-based recovery if split failed (len(parts) < len(headers))
            if len(parts) < len(headers):
                anchor_idx = -1
                regex_anchor = None

                if category == 'attraction' and 'latitude' in headers:
                    # Find first float pattern
                    regex_anchor = r'\s+(-?\d+\.\d+)\s+'
                elif category == 'restaurant' and 'average cost' in headers:
                    # Find first int pattern (cost)
                    regex_anchor = r'\s+(\d+)\s+'
                elif category == 'accommodation' and 'price' in headers:
                    # Find price float pattern
                    regex_anchor = r'\s+(\d+(?:\.\d+)?)\s+'

                if regex_anchor:
                    match = re.search(regex_anchor, line)
                    if match:
                        name_part = line[:match.start()].strip()
                        rest_part = line[match.start():].strip()
                        # Re-split the rest
                        rest_parts = re.split(r'\s{2,}', rest_part)
                        parts = [name_part] + rest_parts

            # Map to headers
            for i, h in enumerate(headers):
                if i < len(parts):
                    row[h] = parts[i]
            results.append(row)
        return results

    valid_transport = []
    valid_accoms = []
    valid_restaurants = []
    valid_attractions = []

    for item in reference_info:
        desc = item.get('Description', '').strip()
        content = item.get('Content', '').strip()
        desc_lower = desc.lower()

        # Transport
        if 'from ' in desc_lower and 'to ' in desc_lower:
            m_route = re.search(r'from\s+([A-Za-z\.\s]+?)\s+to\s+([A-Za-z\.\s]+)', desc, re.IGNORECASE)
            if not m_route: continue
            r_origin, r_dest = m_route.group(1).strip(), m_route.group(2).strip()

            # Only filter if we have absolutely no match in known cities (loose filter)
            if r_origin.lower() not in known_cities and r_dest.lower() not in known_cities:
                continue

            t_type = 'Other'
            if 'flight' in desc_lower: t_type = 'Flight'
            elif 'taxi' in desc_lower: t_type = 'Taxi'
            elif 'driving' in desc_lower: t_type = 'Self-driving'

            if avoid_flying and t_type == 'Flight': continue
            if avoid_driving and t_type == 'Self-driving': continue

            if t_type == 'Flight':
                rows = parse_table(content, 'flight')
                for row in rows:
                    price = clean_cost(row.get('price', 'inf'))
                    if price == 0 or price == float('inf'): continue
                    total_cost = price * people
                    if total_cost <= budget:
                        valid_transport.append({
                            'origin': r_origin, 'dest': r_dest, 'cost': total_cost, 'type': 'Flight',
                            'desc': f"Flight {row.get('flight number','')}, {r_origin}->{r_dest}, Dep: {row.get('departure time','')}, Arr: {row.get('arrival time','')}, Total: ${total_cost:.0f}"
                        })
            else:
                # Taxi/Driving
                m_cost = re.search(r'cost:\s*([\d\.]+)', content)
                base_cost = float(m_cost.group(1)) if m_cost else 0.0
                real_cost = base_cost

                # Taxi usually per car, Driving usually per car (gas)
                # Assuming 4 pax per taxi, 5 per car
                if t_type == 'Taxi': real_cost = base_cost * math.ceil(people / 4.0)
                if t_type == 'Self-driving': real_cost = base_cost * math.ceil(people / 5.0)

                if real_cost <= budget:
                    dur = re.search(r'duration:\s*([^,]+)', content)
                    dist = re.search(r'distance:\s*([^,]+)', content)
                    d_str = dur.group(1) if dur else "?"
                    k_str = dist.group(1) if dist else "?"
                    valid_transport.append({
                        'origin': r_origin, 'dest': r_dest, 'cost': real_cost, 'type': t_type,
                        'desc': f"{t_type}, {r_origin} to {r_dest}, duration: {d_str}, distance: {k_str}, cost: {int(real_cost)}"
                    })
            continue

        # Entities
        m_city = re.search(r'in\s+([A-Za-z\.\s]+)$', desc, re.IGNORECASE)
        if not m_city: continue
        city_name = m_city.group(1).strip()
        # Loose check: if it's in known_cities or destination is a state matching this city
        if city_name.lower() not in known_cities:
             pass

        if 'attraction' in desc_lower:
            rows = parse_table(content, 'attraction')
            for row in rows:
                if row.get('name'):
                    valid_attractions.append({'city': city_name, 'name': row['name']})

        elif 'restaurant' in desc_lower:
            rows = parse_table(content, 'restaurant')
            for row in rows:
                cost = clean_cost(row.get('average cost', 0))
                cuisines = row.get('cuisines', '')
                is_match = any(tc in cuisines.lower() for tc in target_cuisines) if target_cuisines else True
                valid_restaurants.append({
                    'city': city_name, 'name': row.get('name'), 'cuisines': cuisines,
                    'cost': cost, 'rating': row.get('aggregate rating', '0'), 'is_match': is_match
                })

        elif 'accommodation' in desc_lower:
            rows = parse_table(content, 'accommodation')
            for row in rows:
                price = clean_cost(row.get('price', 0))
                rtype = row.get('room type', '')
                rules = row.get('house_rules', '').lower()
                min_n = clean_cost(row.get('minimum nights', 1))
                try: max_occ = float(row.get('maximum occupancy', 1))
                except: max_occ = 1.0

                if require_entire and 'entire' not in rtype.lower(): continue
                if has_pets and 'no pets' in rules: continue
                if total_nights < min_n: continue

                # Occupancy check
                rooms_needed = 1
                if 'entire' not in rtype.lower(): rooms_needed = math.ceil(people / max_occ)
                elif max_occ < people: continue

                valid_accoms.append({
                    'city': city_name, 'name': row.get('name'), 'type': rtype,
                    'price': price, 'rules': rules
                })

    # --- 4. Output Generation ---
    output = []
    output.append(f"Analysis: People={people}, Budget=${budget}, Duration={total_nights} days.")
    output.append(f"Constraints: NoFlight={avoid_flying}, NoDrive={avoid_driving}, Pets={has_pets}")
    output.append("")

    output.append("### TRANSPORTATION")
    if not valid_transport:
        output.append("No valid transportation options found.")
    else:
        # Group by route
        routes = {}
        for t in valid_transport:
            key = f"{t['origin']} -> {t['dest']}"
            if key not in routes: routes[key] = []
            routes[key].append(t)
        for route, opts in sorted(routes.items()):
            output.append(f"Route: {route}")
            for opt in opts:
                output.append(f"- {opt['desc']}")
    output.append("")

    # Group entities by City
    all_cities = sorted(list(set([x['city'] for x in valid_accoms + valid_restaurants + valid_attractions])))

    for city in all_cities:
        output.append(f"### CITY: {city}")

        # Accommodations
        city_acc = [a for a in valid_accoms if a['city'] == city]
        city_acc.sort(key=lambda x: x['price'])
        output.append(f"**Accommodations** ({len(city_acc)} found):")
        for a in city_acc[:10]: # Limit to top 10 cheap options
            output.append(f"- {a['name']} | {a['type']} | Price: ${a['price']:.0f} | Rules: {a['rules']}")
        if not city_acc: output.append("- None matching constraints.")

        # Restaurants
        city_rst = [r for r in valid_restaurants if r['city'] == city]
        # Sort by match first, then rating, then cost
        city_rst.sort(key=lambda x: (not x['is_match'], -float(x['rating']) if x['rating'].replace('.','').isdigit() else 0))
        output.append(f"**Restaurants** ({len(city_rst)} found):")
        for r in city_rst[:15]:
            match_mark = "[MATCH] " if r['is_match'] else ""
            output.append(f"- {match_mark}{r['name']} | {r['cuisines']} | Rating: {r['rating']} | AvgCost: ${r['cost']:.0f}")
        if not city_rst: output.append("- None found.")

        # Attractions
        city_att = [a['name'] for a in valid_attractions if a['city'] == city]
        output.append(f"**Attractions** ({len(city_att)} found):")
        if city_att:
            output.append(", ".join(city_att[:20]))
        else:
            output.append("- None found.")
        output.append("")

    final_answer_text = "\n".join(output)
    return self.make_final_answer("Data filtering and parsing completed based on extracted constraints.", final_answer_text)

def forward(self, taskInfo):
    import re
    import math
    import json

    # --- 1. Input Extraction ---
    # Extract data from taskInfo.content
    # The content might be a dict or a JSON string
    content = taskInfo.content
    if isinstance(content, dict):
        input_data = content
    elif isinstance(content, str):
        try:
            input_data = json.loads(content)
        except:
            input_data = {}
    else:
        input_data = {}

    # --- Helper: Clean Text ---
    def clean_text(text):
        if not text: return ""
        text = str(text)
        # Remove text in parentheses e.g. "City (State)" -> "City "
        text = re.sub(r'\(.*?\)', '', text)
        # Remove punctuation for cleaner matching, except hyphens/spaces
        text = re.sub(r'[^\w\s-]', '', text)
        return text.strip().lower()

    plan = input_data.get('draft_itinerary', [])
    constraints = input_data.get('constraints', {})
    context_str = input_data.get('filtered_context', '')

    # Default values if constraints are missing
    try:
        budget = float(constraints.get('budget', 0) or 0)
        people_count = int(constraints.get('people_count', 1) or 1)
        duration_days = int(constraints.get('duration_days', 0) or 0)
    except:
        budget = 10000
        people_count = 1
        duration_days = 0

    # --- 2. Initial Structure & Error Check ---
    errors = []

    # Check if plan is a list
    if not isinstance(plan, list):
        return self.make_final_answer("Invalid Input", {
            "validation_report": {
                "is_valid": False,
                "errors": ["Plan format is invalid (not a list)."],
                "final_cost": 0
            },
            "calculated_cost": 0
        })

    # Check for empty plan
    if not plan:
        return self.make_final_answer("Empty Plan", {
            "validation_report": {
                "is_valid": False,
                "errors": ["Plan is empty."],
                "final_cost": 0
            },
            "calculated_cost": 0
        })

    # Check for error messages in the plan content
    first_item = plan[0]
    if isinstance(first_item, dict):
        # Case-insensitive check for error keys
        for k, v in first_item.items():
            if 'error' in k.lower() or 'message' in k.lower():
                # If the value looks like an error description
                if isinstance(v, str) and len(v) > 10:
                    return self.make_final_answer("Planner Error", {
                        "validation_report": {
                            "is_valid": False,
                            "errors": [f"Planner returned an error: {v}"],
                            "final_cost": 0
                        },
                        "calculated_cost": 0
                    })

    # Check duration constraint
    if duration_days > 0 and len(plan) != duration_days:
        errors.append(f"Plan has {len(plan)} days, but constraints require {duration_days} days.")

    # --- 3. Robust Database Parsing ---
    db = {
        'flights': {},     # ID -> Price
        'hotels': {},      # Name -> {price, occupancy}
        'restaurants': {}, # Name -> Cost
        'attractions': [], # Name
        'transport': {}    # Key -> Cost
    }

    sections = re.split(r'(?=Description:)', context_str)
    for section in sections:
        if not section.strip(): continue
        lower_sec = section.lower()
        content_match = re.search(r'Content:(.*)', section, re.DOTALL)
        if not content_match: continue
        lines = [l.strip() for l in content_match.group(1).split('\n') if l.strip()]

        # Parse Flights
        if 'flight' in lower_sec:
            for line in lines:
                # Look for F followed by digits
                m_id = re.search(r'(F\d+)', line)
                # Look for price (digits potentially with decimal)
                m_price = re.search(r'\s+(\d+\.?\d*)\s+', line)
                if m_id and m_price:
                    db['flights'][m_id.group(1)] = float(m_price.group(1))

        # Parse Restaurants
        elif 'restaurant' in lower_sec:
            for line in lines:
                # Format: Name Cost Cuisines Rating City
                # We look for the first number which is usually cost or rating.
                # However, the cost is usually the first separate number after the name.
                # Strategy: Split by multiple spaces
                parts = re.split(r'\s{2,}', line)
                if len(parts) >= 2:
                    # Skip header
                    if 'average cost' in parts[1].lower(): continue

                    name = clean_text(parts[0])
                    cost = 0
                    # Try to find cost in the second column
                    try:
                        cost = float(re.sub(r'[^\d.]', '', parts[1]))
                    except:
                        pass

                    if cost > 0:
                        db['restaurants'][name] = cost

        # Parse Accommodations
        elif 'accommodation' in lower_sec:
            for line in lines:
                parts = re.split(r'\s{2,}', line)
                if len(parts) >= 2:
                    if 'price' in parts[1].lower(): continue

                    name = clean_text(parts[0])
                    price = 0
                    try:
                        price = float(re.sub(r'[^\d.]', '', parts[1]))
                    except: pass

                    # Look for occupancy in subsequent parts
                    occ = 2
                    # Heuristic: look for small integer (1-20) in later columns
                    for p in parts[2:]:
                        try:
                            val = float(re.sub(r'[^\d.]', '', p))
                            if 1 <= val <= 20 and val.is_integer():
                                occ = int(val)
                                break # Assume first small int is occupancy
                        except: pass

                    if price > 0:
                        db['hotels'][name] = {'price': price, 'occupancy': occ}

        # Parse Attractions
        elif 'attraction' in lower_sec:
            for line in lines:
                parts = re.split(r'\s{2,}', line)
                if parts and 'name' not in parts[0].lower():
                    db['attractions'].append(clean_text(parts[0]))

        # Parse Transport (Taxi/Self-driving)
        elif 'taxi' in lower_sec or 'self-driving' in lower_sec:
            # Format: "mode, from Origin to Dest, ... cost: X"
            for line in lines:
                if 'cost' in line.lower():
                    try:
                        cost_m = re.search(r'cost:\s*(\d+)', line.lower())
                        if cost_m:
                            cost = float(cost_m.group(1))
                            # Extract Origin and Dest
                            from_to = re.search(r'from\s+(.*?)\s+to\s+(.*?)(,|$)', line, re.IGNORECASE)
                            if from_to:
                                origin = clean_text(from_to.group(1))
                                dest = clean_text(from_to.group(2))
                                mode = "self-driving" if "self-driving" in lower_sec else "taxi"
                                # Store with a standardized key
                                key = f"{mode}_{origin}_{dest}"
                                db['transport'][key] = cost
                    except: pass

    # --- 4. Validation Loop ---
    total_cost = 0.0
    cars_needed = math.ceil(people_count / 4)

    # State tracking
    current_location = clean_text(constraints.get('origin_city', ''))

    normalized_plan = []
    for day in plan:
        if isinstance(day, dict):
            normalized_plan.append({k.lower().strip(): v for k, v in day.items()})
        else:
            normalized_plan.append({})

    for i, day in enumerate(normalized_plan):
        d_idx = i + 1

        # 4a. Validate Current City & Transition
        curr_city_raw = day.get('current_city', '-')
        if not curr_city_raw or curr_city_raw == '-':
            errors.append(f"Day {d_idx}: 'current_city' is missing.")
            continue

        curr_city_clean = clean_text(curr_city_raw)

        # Detect Travel
        # Format expected: "from Origin to Dest"
        is_travel_day = 'from' in curr_city_clean and 'to' in curr_city_clean

        if is_travel_day:
            # Extract implied origin and dest from city string
            m = re.search(r'from\s+(.*?)\s+to\s+(.*)', curr_city_clean)
            if m:
                origin = m.group(1).strip()
                dest = m.group(2).strip()

                # Check continuity
                if current_location and origin not in current_location and current_location not in origin:
                    # Allow soft mismatch but flag if completely different
                    pass # Relaxed check as city names might vary slightly

                current_location = dest # Update location

                # Validate Transportation
                trans = day.get('transportation', '-')
                if not trans or trans == '-':
                    errors.append(f"Day {d_idx}: Travel detected but 'transportation' is missing.")
                else:
                    trans_clean = clean_text(trans)
                    # Check Flight
                    f_match = re.search(r'(F\d+)', trans)
                    if f_match:
                        fid = f_match.group(1)
                        if fid in db['flights']:
                            total_cost += db['flights'][fid] * people_count
                        else:
                            errors.append(f"Day {d_idx}: Flight {fid} not found in database.")
                    # Check Ground Transport
                    else:
                        # Try to match with DB transport keys
                        # Key format: "mode_origin_dest"
                        matched_transport = False
                        for key, cost in db['transport'].items():
                            mode_key, origin_key, dest_key = key.split('_')
                            # Check if mode, origin, and dest are in the transportation string or city string
                            # Heuristic: trans string usually contains "Self-driving" or "Taxi"
                            if mode_key in trans_clean and origin_key in curr_city_clean and dest_key in curr_city_clean:
                                total_cost += cost * cars_needed
                                matched_transport = True
                                break
                        if not matched_transport:
                             errors.append(f"Day {d_idx}: valid ground transport (Self-driving/Taxi) matching route not found in database for '{trans}'.")
        else:
            # Stationary day
            # current_location should match curr_city_clean approximately
            pass

        # 4b. Validate Accommodation
        acc = day.get('accommodation', '-')
        if acc and acc != '-':
            acc_clean = clean_text(acc.split(',')[0])
            found = False
            for h_name, h_data in db['hotels'].items():
                if h_name in acc_clean or acc_clean in h_name:
                    rooms = math.ceil(people_count / h_data['occupancy'])
                    total_cost += rooms * h_data['price']
                    found = True
                    break
            if not found:
                errors.append(f"Day {d_idx}: Accommodation '{acc}' not found in database.")
        elif i < len(plan) - 1:
            # If not the last day, accommodation is usually required unless explicit overnight travel
            # We won't strict fail but it is suspicious
            pass

        # 4c. Validate Meals
        for meal in ['breakfast', 'lunch', 'dinner']:
            item = day.get(meal, '-')
            if item and item != '-':
                item_clean = clean_text(item.split(',')[0])
                found = False
                for r_name, cost in db['restaurants'].items():
                    if r_name in item_clean or item_clean in r_name:
                        total_cost += cost * people_count
                        found = True
                        break
                if not found:
                    errors.append(f"Day {d_idx}: {meal.title()} '{item}' not found in database.")

        # 4d. Validate Attractions
        att = day.get('attraction', '-')
        if att and att != '-':
            for a in att.split(';'):
                if not a.strip(): continue
                a_clean = clean_text(a.split(',')[0])
                found = False
                for db_att in db['attractions']:
                    if db_att in a_clean or a_clean in db_att:
                        found = True
                        break
                if not found:
                    errors.append(f"Day {d_idx}: Attraction '{a}' not found in database.")

    # --- 5. Final Budget Check ---
    if total_cost > budget:
        errors.append(f"Total cost ${total_cost:.2f} exceeds budget ${budget:.2f}.")

    return self.make_final_answer("Validation logic applied", {
        "validation_report": {
            "is_valid": len(errors) == 0,
            "errors": errors,
            "final_cost": total_cost
        },
        "calculated_cost": total_cost
    })

def forward(self, taskInfo):
    # ---------- Step 1: Process input ----------
    # Extract input data from taskInfo
    input_data = taskInfo.content if isinstance(taskInfo.content, dict) else {}
    if not input_data and isinstance(taskInfo.content, str):
        try:
            input_data = json.loads(taskInfo.content)
        except:
            input_data = {}

    draft = input_data.get('draft_itinerary', [])
    report = input_data.get('validation_report', {})
    context_raw = input_data.get('context')
    constraints = input_data.get('constraints', {})

    # Determine if we need to regenerate from scratch
    # If draft has errors or is empty, or validation failed, regenerate.
    needs_regeneration = False
    if not draft or (isinstance(draft, list) and len(draft) > 0 and 'error' in draft[0]):
        needs_regeneration = True
    elif not report.get('is_valid', False):
        needs_regeneration = True

    # If the draft is actually valid, just return it
    if not needs_regeneration:
        return self.make_final_answer("Draft is valid, no regeneration needed.", {"final_itinerary": draft})

    # ---------- Step 2: Prepare Context ----------
    # We MUST use raw context for regeneration to ensure we see all transport links
    if context_raw and isinstance(context_raw, (list, dict)):
        context_str = json.dumps(context_raw, indent=2)
    else:
        context_str = input_data.get('filtered_context', '')

    # ---------- Step 3: Extract Constraints ----------
    duration = constraints.get('duration_days', 7)
    budget = constraints.get('budget', 0)
    origin = constraints.get('origin_city', 'Origin')
    dest = constraints.get('destination_city', 'Destination')
    start_date = constraints.get('start_date', '')
    people = constraints.get('people_count', 1)

    accommodation_constraints = ""
    if "pets" in str(constraints).lower() or "pet" in str(constraints).lower():
        accommodation_constraints += "User likely has pets. EXCLUDE accommodations with 'No pets' in house_rules. "
    else:
        # Add a safe default or checking mechanism
        accommodation_constraints += "Check if pets are mentioned. "

    accommodation_constraints += "Prefer 'Entire home/apt' if strictly requested or typically preferred for groups."

    cuisine_preferences = "Mexican, Italian, Mediterranean, Indian, or local specialties"

    # ---------- Step 4: Construct Instruction ----------
    cot_instruction = f"""
    You are an expert travel planner. The user wants a {duration}-day trip for {people} people from {origin} to {dest} with a budget of ${budget}.

    Context Data:
    {context_str}

    Task:
    Generate a valid JSON itinerary based STRICTLY on the provided Context.

    User Request: Create the plan for {people} people, {duration} days, from {origin} to {dest}. Start date: {start_date}. Ensure all fields are filled using Context data strictly. Handle any multi-city travel if the data implies it.

    **CRITICAL: Route Discovery**
    The destination '{dest}' might be a region (e.g., 'Colorado'). You must scan the 'Description' fields in the Context for transport options starting from {origin} to find the actual entry city (e.g., 'from {origin} to [City]'). Then look for connections between cities (e.g., 'from [City] to [Next City]') to form a complete loop or path ending back at {origin}. Do not invent flights; if 'No flight' is listed, use 'Self-driving' or 'Taxi' found in the context.

    Rules:
    1. **Transport**: Use exact strings from context (e.g., "Self-driving, from ... cost: ..."). 
    2. **Budget**: Total cost must be under ${budget}. Sum: Transport + Accommodation (per night * nights) + Food (per person) + Attractions.
    3. **Accommodations**: 
       - Constraints: {accommodation_constraints}
       - Ensure the accommodation city matches the current city.
    4. **Dining**: Select restaurants matching these cuisines: {cuisine_preferences}.
    5. **Structure**: 
       - Plan for exactly {duration} days.
       - 'current_city' field: 'from [Start] to [End]' on travel days, otherwise '[City]'.
       - 'accommodation': '-' on the final return day.

    Output Format:
    Return a single JSON object (no markdown):
    {{
      "thought_process": "Identify route: Origin -> City A -> City B -> Origin. Calculate costs...",
      "itinerary": [
        {{
          "days": 1,
          "current_city": "from [Start] to [End]",
          "transportation": "Full string from context",
          "breakfast": "Name, City",
          "attraction": "Name, City; Name, City",
          "lunch": "Name, City",
          "dinner": "Name, City",
          "accommodation": "Name, City"
        }}
      ]
    }}
    """

    # Instantiate a new LLM agent specifically for CoT
    cot_agent = LLMAgentBase(['thinking', 'answer'], 'Refinement Agent',  model=self.node_model, temperature=0.0)

    # Prepare the inputs for the CoT agent
    cot_agent_inputs = [taskInfo]

    # ---------- Step 5: Call LLM ----------
    thinking, answer = cot_agent(cot_agent_inputs, cot_instruction)

    # Handle response format
    try:
        response_text = answer.content
        response_text = re.sub(r'```json|```', '', response_text).strip()
        parsed_json = json.loads(response_text)

        final_plan = []
        if 'itinerary' in parsed_json and isinstance(parsed_json['itinerary'], list):
            final_plan = parsed_json['itinerary']
        elif isinstance(parsed_json, list):
            final_plan = parsed_json
        else:
             # Fallback search
            for key, value in parsed_json.items():
                if isinstance(value, list):
                    final_plan = value
                    break

        if not final_plan:
            # If still empty, return error
            result = {"final_itinerary": [{"error": "Failed to parse itinerary from LLM response."}]}
        else:
            result = {"final_itinerary": final_plan}

    except Exception as e:
        print(f"Refinement Agent Error: {e}")
        result = {"final_itinerary": [{"error": f"Error generating itinerary: {str(e)}"}]}

    final_answer = self.make_final_answer(thinking.content, result)
    return final_answer
